def contar_maiores(valores, limite):
    contador = 0
    for valor in valores:
        if valor > limite:
            contador += 1
    return contador

lote_a = [10, 50, 70, 20]
lote_b = [100, 30, 20]

print(f'Lote A: {contar_maiores(lote_a, 40)}')
print(f'Lote B: {contar_maiores(lote_b, 40)}')
